import { describe, it, expect } from "vitest";
import { quote, createPolicy, processClaim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote", () => {
    it.todo("should charge only the processing fee for an empty item list");
    it.todo("should compute base premium for a single sword");
    it.todo("should sum base premiums for multiple items");
    it.todo("should apply block pricing for exactly 3 alike components");
    it.todo("should apply cursed surcharge to the affected item only");
    it.todo("should apply high-enchantment surcharge to items with enchantment >= 5");
    it.todo("should apply loyalty discount for customers with >= 2 years");
    it.todo("should apply first-insurance surcharge for a customer's first contract");
    it.todo("should apply follow-up discount for subsequent contracts");
    it.todo("should round premiums up in MHPCO's favor");
  });

  describe("claim", () => {
    it.todo("should deduct 100 G per damage event");
    it.todo("should fully reimburse dragon-material items minus deductible");
    it.todo("should reimburse high-enchantment items (>= 8) at 50% minus deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across successive claims");
  });
});

