export type Customer = {
  yearsWithMHPCO: number;
};

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Policy = {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_PRICE = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: COMPONENT_BASE_PREMIUM,
};

export const quote = (
  customer: Customer,
  items: Item[],
  contractNumber: number
): number => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  let basePremium = 0;
  for (const [type, count] of Object.entries(counts)) {
    basePremium += count === 3 && BASE_PREMIUMS[type] === COMPONENT_BASE_PREMIUM
      ? COMPONENT_BLOCK_PRICE
      : count * BASE_PREMIUMS[type];
  }
  let cursedSurcharge = 0;
  for (const item of items) {
    if (item.cursed) cursedSurcharge += BASE_PREMIUMS[item.type] * CURSED_SURCHARGE_RATE;
  }
  let highEnchantmentSurcharge = 0;
  for (const item of items) {
    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) highEnchantmentSurcharge += BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  return basePremium + cursedSurcharge + highEnchantmentSurcharge - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
};

export const createPolicy = (items: Item[]): Policy => {
  return undefined as unknown as Policy;
};

export const processClaim = (
  policy: Policy,
  incident: Incident
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

